import {
  Box,
  IconButton,
  SxProps,
  TableCell,
  TableRow,
  Theme,
  Tooltip,
} from "@mui/material";
import { type ReactNode, useCallback, useState } from "react";

import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";
import { IconChevronDown } from "@dfp/react-icons";
import { createCheckedContext } from "@dfp/react-utils";

import { useTT } from "../../../useTT.ts";
import { useSelectedColumn } from "../../SelectionContext.tsx";
import { cashflowLayoutConfig } from "../../cashflow-layout.config.ts";
import type { CategoryType } from "../types/index.ts";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryContextValue = {
  isExpanded: boolean;
  toggleExpanded: () => void;
};

const [CashflowCategoryProvider, useCashflowCategory] =
  createCheckedContext<CashflowCategoryContextValue>("CashflowCategoryContext");

type CashflowCategoryProps = {
  children: ReactNode;
  defaultExpanded?: boolean;
};

export function CashflowCategory({
  children,
  defaultExpanded = true,
}: CashflowCategoryProps) {
  const [isExpanded, setIsExpanded] = useState(defaultExpanded);

  const toggleExpanded = () => setIsExpanded((prev) => !prev);

  return (
    <CashflowCategoryProvider value={{ isExpanded, toggleExpanded }}>
      {children}
    </CashflowCategoryProvider>
  );
}

type CashflowCategoryHeaderProps = {
  children: ReactNode;
};

