          key={period.id}
          scope="col"
          onClick={() => setPeriod(dayjs(period.dateFrom))}
          aria-selected={selectedColumn === index}
          sx={{
            textAlign: "center",
            cursor: "pointer",
            borderTop: 2,
            borderTopColor:
              selectedColumn === index ? "text.secondary" : "transparent",
            borderRight: 1,
            borderRightColor:
              selectedColumn === index
                ? "custom.borderSecondary"
                : "background.paper",
            borderLeft: 1,
            borderLeftColor:
              selectedColumn === index
                ? "custom.borderSecondary"
                : "background.paper",
            borderBottomColor: "custom.borderSecondary",
            backgroundColor: "background.paper",
            fontWeight: 600,
            fontSize: 12,
            whiteSpace: "nowrap",
            boxSizing: "border-box",
          }}
        >
          {formatPeriodLabel({
            dateFrom: period.dateFrom,
            dateTo: period.dateTo,
            interval,
          })}
        </TableCell>
      ))}
    </TableRow>
  );
}

